import { useState } from "react";

export default function Register() {
  const [form, setForm] = useState({
    name: "",
    aadhaar: "",
    dob: "",
    center_id: "",
    date: ""
  });

  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  const submit = async () => {
    try {
      const res = await fetch("http://localhost:5000/register", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(form)
      });

      const text = await res.text();
      alert(text);
    } catch (err) {
      alert("Error");
    }
  };

  return (
    <div>
      <h2>Register</h2>

      <input name="name" placeholder="Name" onChange={handleChange} /><br /><br />
      <input name="aadhaar" placeholder="Aadhaar" onChange={handleChange} /><br /><br />
      <input type="date" name="dob" onChange={handleChange} /><br /><br />
      <input name="center_id" placeholder="Center ID" onChange={handleChange} /><br /><br />
      <input type="date" name="date" onChange={handleChange} /><br /><br />

      <button onClick={submit}>Submit</button>
    </div>
  );
}
